import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';

function AddCourse() {
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [classId, setClassId] = useState('');
  const [subjectId, setSubjectId] = useState('');
  const [classes, setClasses] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [file, setFile] = useState(null);

  useEffect(() => {
    if (user?.role === "teacher") {
      fetch("http://localhost:3001/classes")
        .then((res) => res.json())
        .then((data) => setClasses(Array.isArray(data) ? data : []))
        .catch((error) => toast.error("Ошибка загрузки классов"));
      fetch(`http://localhost:3001/teacher_subjects?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((teacherSubjects) => {
          const subjectIds = teacherSubjects.map((ts) => ts.subjectId);
          if (subjectIds.length > 0) {
            fetch(`http://localhost:3001/subjects?id=${subjectIds.join("&id=")}`)
              .then((res) => res.json())
              .then((data) => setSubjects(Array.isArray(data) ? data : []))
              .catch((error) => toast.error("Ошибка загрузки предметов"));
          }
        })
        .catch((error) => toast.error("Ошибка загрузки данных преподавателя"));
    }
  }, [user]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const newCourse = {
      name,
      description,
      classId: parseInt(classId),
      teacherId: user.id,
      subjectId: parseInt(subjectId),
    };
    try {
      const response = await fetch("http://localhost:3001/courses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newCourse),
      });
      if (response.ok) {
        const course = await response.json();
        toast.success("Курс добавлен!");
        if (file) {
          const formData = new FormData();
          formData.append("file", file);
          const uploadResponse = await fetch("http://localhost:3002/upload", {
            method: "POST",
            body: formData,
          });
          if (uploadResponse.ok) {
            const { filename, originalName } = await uploadResponse.json();
            const fileData = {
              courseId: course.id,
              filename,
              originalName,
              path: `uploads/${filename}`,
              createdAt: new Date().toISOString(),
            };
            await fetch("http://localhost:3001/files", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify(fileData),
            });
          }
        }
        navigate('/courses');
      } else {
        toast.error("Не удалось добавить курс");
      }
    } catch (error) {
      console.error("Add course error:", error);
      toast.error("Сетевая ошибка при добавлении курса");
    }
  };

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Добавить курс</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label htmlFor="name" className="form-label">Название курса</label>
              <input
                type="text"
                id="name"
                className="form-control"
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
              />
            </div>
            <div className="mb-3">
              <label htmlFor="description" className="form-label">Описание</label>
              <textarea
                id="description"
                className="form-control"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
            <div className="mb-3">
              <label htmlFor="class" className="form-label">Класс</label>
              <select
                id="class"
                className="form-select"
                value={classId}
                onChange={(e) => setClassId(e.target.value)}
                required
              >
                <option value="">-- Выберите класс --</option>
                {classes.map((cls) => (
                  <option key={cls.id} value={cls.id}>
                    {cls.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="mb-3">
              <label htmlFor="subject" className="form-label">Предмет</label>
              <select
                id="subject"
                className="form-select"
                value={subjectId}
                onChange={(e) => setSubjectId(e.target.value)}
                required
              >
                <option value="">-- Выберите предмет --</option>
                {subjects.map((subject) => (
                  <option key={subject.id} value={subject.id}>
                    {subject.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="mb-3">
              <label htmlFor="file" className="form-label">Файл</label>
              <input
                type="file"
                id="file"
                className="form-control"
                onChange={(e) => setFile(e.target.files[0])}
              />
            </div>
            <button type="submit" className="btn btn-primary w-100">Добавить</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default AddCourse;
